'use client';

import { useState } from 'react';
import React from 'react';

// 1. Definicja Typu Danych Zwracanych Przez Backend (Spring Boot)
// Zgodne z Map<String, BigDecimal> z ObligacjeController.java
interface ObliczeniaWynik {
  // TypeScript przyjmuje, że to są liczby, które zostały przesłane jako JSON
  daily: number;
  monthly: number;
  yearly: number;
}

// Stała URL Twojego Back-endu
const API_URL = 'http://localhost:8080/api/calc';

export default function KalkulatorObligacjiPage() {
    
    // Inicjalizacja stanu
    const [kwota, setKwota] = useState<number>(1000); // Wartość początkowa dla inputa
    const [oprocentowanie, setOprocentowanie] = useState<number>(5.0); // Wartość początkowa dla inputa
    
    // Jawna deklaracja typu: może być ObliczeniaWynik LUB null
    const [wyniki, setWyniki] = useState<ObliczeniaWynik | null>(null); 
    
    // Jawna deklaracja typu: może być string LUB null (rozwiązuje błąd 'SetStateAction<null>')
    const [error, setError] = useState<string | null>(null); 

    // --- LOGIKA POBIERANIA DANYCH Z API ---
    const obliczOprocentowanie = async (e: React.MouseEvent) => {
        e.preventDefault(); // Zapobiega domyślnej akcji formularza (przeładowaniu strony)
        
        // Wyczyść poprzednie błędy i wyniki
        setError(null);
        setWyniki(null);

        // Walidacja podstawowa
        if (kwota <= 0 || oprocentowanie <= 0) {
            setError("Kwota i oprocentowanie muszą być większe od zera.");
            return;
        }

        // 2. Składanie URL z Query Params
        const fullUrl = `${API_URL}?kwota=${kwota}&oprocentowanie=${oprocentowanie}`;

        try {
            const response = await fetch(fullUrl, {
                method: 'GET',
                // Spring Boot dzięki @CrossOrigin już ustawi nagłówek "Access-Control-Allow-Origin"
            });

            // Sprawdzenie, czy status HTTP jest pomyślny (np. 200 OK)
            if (!response.ok) {
                // Jeśli serwer zwrócił błąd HTTP (np. 400, 500)
                throw new Error(`Błąd serwera! Status: ${response.status}`);
            }

            // 3. Deserializacja JSON
            const data: ObliczeniaWynik = await response.json();
            
            setWyniki(data);

        } catch (err) {
            // W przypadku błędu sieciowego (np. Spring Boot nie działa)
            const errorMessage = (err instanceof Error) 
                ? err.message 
                : "Wystąpił nieznany błąd podczas łączenia z API.";
            
            setError(`Nie udało się połączyć z back-endem: ${errorMessage}. Sprawdź, czy Spring działa na porcie 8080.`);
        }
    };

    // --- RENDEROWANIE ---
    return (
        <div style={{ padding: '20px', maxWidth: '600px', margin: '0 auto', fontFamily: 'Arial, sans-serif' }}>
            <h1>💰 Kalkulator Obligacji (Spring Boot API)</h1>
            
            <form style={{ display: 'flex', flexDirection: 'column', gap: '15px', padding: '20px', border: '1px solid #ccc', borderRadius: '8px' }}>
                
                <label>
                    Kwota Początkowa:
                    <input 
                        type="number" 
                        value={kwota} 
                        onChange={(e) => setKwota(Number(e.target.value))}
                        style={{ marginLeft: '10px', padding: '8px', border: '1px solid #ddd' }}
                    />
                </label>
                
                <label>
                    Oprocentowanie (%):
                    <input 
                        type="number" 
                        value={oprocentowanie} 
                        onChange={(e) => setOprocentowanie(Number(e.target.value))}
                        style={{ marginLeft: '10px', padding: '8px', border: '1px solid #ddd' }}
                    />
                </label>
                
                <button 
                    onClick={obliczOprocentowanie}
                    style={{ padding: '10px', backgroundColor: 'blue', color: 'white', border: 'none', borderRadius: '4px', cursor: 'pointer' }}
                >
                    Oblicz Zysk
                </button>
            </form>

            {/* WYŚWIETLANIE BŁĘDU */}
            {error && <p style={{ color: 'red', fontWeight: 'bold' }}>⚠️ Błąd: {error}</p>}
            
{/* WYŚWIETLANIE WYNIKÓW */}
{wyniki && (
                <div style={{ marginTop: '20px', borderTop: '2px solid #007bff', paddingTop: '15px' }}>
                    <h2>✅ Wyniki Obliczeń:</h2>
                    <p>
                        Zysk Dzienny: 
                        <span style={{ color: 'green', fontWeight: 'bold' }}>
                            {wyniki.daily.toFixed(2)}
                        </span> 
                        PLN
                    </p>
                    <p>
                        Zysk Miesięczny: 
                        <span style={{ color: 'green', fontWeight: 'bold' }}>
                            {wyniki.monthly.toFixed(2)}
                        </span> 
                        PLN
                    </p>
                    <p>
                        Zysk Roczny: 
                        <span style={{ color: 'green', fontWeight: 'bold' }}>
                            {wyniki.yearly.toFixed(2)}
                        </span> 
                        PLN
                    </p>
                </div>
            )}
        </div>
    );
}